import React, { useState } from "react";

function CompareModels() {
  const [results, setResults] = useState(null);

  const runCompare = async () => {
    const res = await fetch("http://127.0.0.1:5000/compare", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({})
    });

    const data = await res.json();

    if (data.status === "success") {
      setResults(data.results);
    }
  };

  const renderMetrics = (name, metrics) => {
    if (!metrics) return null;

    return (
      <div style={{ marginTop: "20px", border: "1px solid #ccc", padding: "15px" }}>
        <h3>{name}</h3>

        <p>TPR: {metrics.TPR?.toFixed(2)}%</p>
        <p>FNR: {metrics.FNR?.toFixed(2)}%</p>
        <p>FPR: {metrics.FPR?.toFixed(2)}%</p>
        <p>TNR: {metrics.TNR?.toFixed(2)}%</p>
        <p>F1 Score: {metrics.F1?.toFixed(2)}%</p>

        {/* 🔥 Confusion Matrix */}
        <p>
          Confusion → TN: {metrics.TN ?? 0} | FP: {metrics.FP ?? 0} | FN: {metrics.FN ?? 0} | TP: {metrics.TP ?? 0}
        </p>
      </div>
    );
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>📊 Model Performance</h2>

      <button onClick={runCompare}>Run Comparison</button>

      {results && (
        <div>
          {renderMetrics("OCSVM", results.OCSVM)}
          {renderMetrics("DBSCAN", results.DBSCAN)}
        </div>
      )}
    </div>
  );
}

export default CompareModels;
